amount.onSubmit:
{{
  storeValue('bulkAdvances', (appsmith.store.bulkAdvances || []).map(r => 
    r.id === tblAdvancePreview.triggeredRow.id 
    ? { 
        ...r, 
        amount: Number(tblAdvancePreview.updatedRow.amount || r.amount),
        payment_mode: tblAdvancePreview.updatedRow.payment_mode || r.payment_mode,
        from_account_id: tblAdvancePreview.updatedRow.from_account_id || r.from_account_id,
        bank_statement_entry_id: tblAdvancePreview.updatedRow.bank_statement_entry_id || r.bank_statement_entry_id
      } 
    : r
  ));
}}

