bank_statement_entry_id.selectOptions:
{{(() => { const tableData = tblAdvancePreview.processedTableData || []; return tableData.length > 0 ? tableData.map((currentRow, currentIndex) => ( 
  getUnconsumedDebits.data.map(debit => ({ 
    label: `${debit.debit_amount} - ₹${debit.consumed_amount}`, 
    value: debit.id 
  })) 
)) :  
  getUnconsumedDebits.data.map(debit => ({ 
    label: `${debit.debit_amount} - ₹${debit.consumed_amount}`, 
    value: debit.id 
  })) 
 })()}}

